// Generated by AI (UnitTest MCP)
use std::collections::HashSet;

use crate::graph::test_support::*;
use crate::model::{NodeType, RelationType};

/// Build a graph exercising every mutation/failure/commit relation the evidence
/// seam recognises, then assert the emitted bundle is self-consistent against
/// the contract Lodestar's `validate_evidence_shape` enforces. This pins the
/// otherwise-unenforced ingestion convention (execution -> modified/failed_on,
/// intent -> refactored): a future break fails here, not silently in production.
#[test]
fn evidence_for_emits_self_consistent_provenance() {
    let s = store();
    add_node(&s, "agent:a", NodeType::Agent, "a", NOW);
    add_node(&s, "execution:e1", NodeType::Execution, "cmd", NOW);
    add_node(&s, "intent:c1", NodeType::Intent, "commit", NOW);
    add_node(&s, "artifact:changed", NodeType::Artifact, "changed", NOW);
    add_node(&s, "artifact:failed", NodeType::Artifact, "failed", NOW);
    add_node(
        &s,
        "artifact:refactored",
        NodeType::Artifact,
        "refactored",
        NOW,
    );

    for (source, target, relation) in [
        ("agent:a", "execution:e1", RelationType::Observed),
        ("agent:a", "intent:c1", RelationType::Observed),
        ("execution:e1", "artifact:changed", RelationType::Modified),
        ("execution:e1", "artifact:failed", RelationType::FailedOn),
        ("intent:c1", "artifact:refactored", RelationType::Refactored),
    ] {
        s.upsert_edge(&raw_edge(source, target, relation, 1.0, 168.0, NOW))
            .unwrap();
    }

    let ev = s
        .evidence_for(Some("task:t"), "a", NOW, NOW + HOUR)
        .unwrap();

    // The scenario must actually exercise each set, or the property is vacuous.
    assert!(!ev.execution_ids.is_empty());
    assert!(!ev.commit_ids.is_empty());
    assert!(!ev.changed_node_ids.is_empty());
    assert!(!ev.failed_node_ids.is_empty());

    let agent_node = format!("agent:{}", ev.agent_id);
    let mutation_sources: HashSet<&str> = ev
        .execution_ids
        .iter()
        .chain(ev.commit_ids.iter())
        .map(String::as_str)
        .collect();
    let execution_sources: HashSet<&str> = ev.execution_ids.iter().map(String::as_str).collect();

    // 1. Every observed event carries agent-attributed observation provenance.
    for event in ev.execution_ids.iter().chain(ev.commit_ids.iter()) {
        assert!(
            ev.provenance.iter().any(|p| {
                p.source_id == agent_node && p.target_id == *event && p.relation == "observed"
            }),
            "event {event} lacks agent observation provenance"
        );
    }
    // 2. Every changed node's mutation source is an execution or a commit.
    for node in &ev.changed_node_ids {
        assert!(
            ev.provenance.iter().any(|p| {
                p.target_id == *node
                    && matches!(p.relation.as_str(), "modified" | "refactored")
                    && mutation_sources.contains(p.source_id.as_str())
            }),
            "changed node {node} lacks a covering mutation source"
        );
    }
    // 3. Every failed node's failure source is an execution.
    for node in &ev.failed_node_ids {
        assert!(
            ev.provenance.iter().any(|p| {
                p.target_id == *node
                    && p.relation == "failed_on"
                    && execution_sources.contains(p.source_id.as_str())
            }),
            "failed node {node} lacks a covering failure source"
        );
    }
    // 4. Successful executions are always a subset of executions.
    assert!(ev
        .successful_execution_ids
        .iter()
        .all(|id| ev.execution_ids.contains(id)));
}
